import { BrowserRouter, Routes, Route, NavLink, Link, useLocation } from 'react-router-dom';
import Dashboard from './pages/Dashboard';
import Teams from './pages/Teams';
import TeamDetail from './pages/TeamDetail';
import Matches from './pages/Matches';
import MatchDetail from './pages/MatchDetail';

function Navbar() {
  const linkClass = ({ isActive }) =>
    `inline-flex items-center gap-2 px-4 py-2 rounded-2xl text-sm font-semibold transition-all ${
      isActive
        ? 'bg-emerald-100 text-emerald-900 shadow-sm'
        : 'text-slate-700 hover:bg-emerald-50 hover:text-emerald-900'
    }`;

  return (
    <nav className="top-nav">
      <div className="nav-inner">
        <Link to="/" className="brand-link">
          <span className="brand-emoji">🏏</span>
          <span className="brand-name">Cricket League Ledger</span>
        </Link>
        <div className="nav-links">
          <NavLink to="/" end className={linkClass}>🏠 Dashboard</NavLink>
          <NavLink to="/teams" className={linkClass}>👥 Teams</NavLink>
          <NavLink to="/matches" className={linkClass}>🏆 Matches</NavLink>
        </div>
      </div>
    </nav>
  );
}

export default function App() {
  const location = useLocation();
  const showHero = location.pathname === '/';

  return (
    <BrowserRouter>
      <div className="app-shell">
        <Navbar />
        <div className="page-shell">
          {showHero && (
            <section className="hero-banner fade-in">
              <div className="hero-card">
                <div>
                  <p className="eyebrow">Cricket ledger for modern squads</p>
                  <h1 className="hero-title">Track teams, matches, expenses and settlements from one polished scorecard.</h1>
                  <p className="hero-copy">
                    Your logic remains the same. The interface now surfaces important actions, page hierarchy, and readable cards so updates appear instantly.
                  </p>
                </div>
                <div className="hero-actions">
                  <Link to="/teams" className="btn-primary">Manage teams</Link>
                  <Link to="/matches" className="btn-muted">View fixtures</Link>
                </div>
              </div>
            </section>
          )}
          <main className="content-shell">
            <Routes>
              <Route path="/" element={<Dashboard />} />
              <Route path="/teams" element={<Teams />} />
              <Route path="/teams/:id" element={<TeamDetail />} />
              <Route path="/matches" element={<Matches />} />
              <Route path="/matches/:id" element={<MatchDetail />} />
            </Routes>
          </main>
        </div>
      </div>
    </BrowserRouter>
  );
}
